package assessment.manager.controllers;

import assessment.manager.dtos.requests.*;
import assessment.manager.dtos.responses.*;
import assessment.manager.services.interfaces.AssessmentService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;

/**
 * REST Controller for managing assessments
 * 
 * This controller provides endpoints for:
 * - Creating new assessments
 * - Retrieving assessments by creator
 * - Auto-grading assessment submissions
 * - Managing assessment settings (timer, randomization, correct answers)
 * 
 * @author Assessment Management System
 * @version 1.0
 */
@RestController
@RequestMapping("/api/v1/assessments")
@RequiredArgsConstructor
@Slf4j
@CrossOrigin(origins = "*")
public class AssessmentController {

    private final AssessmentService assessmentService;

    /**
     * Create a new assessment
     */
    @PostMapping
    public ResponseEntity<AssessmentResponse> createAssessment(
            @Valid @RequestBody CreateAssessmentRequest request) {
        
        log.info("Creating new assessment with title: {}", request.getTitle());
        
        try {
            AssessmentResponse response = assessmentService.createAssessment(request);
            log.info("Assessment created successfully with ID: {}", response.getId());
            return ResponseEntity.status(HttpStatus.CREATED).body(response);
        } catch (Exception e) {
            log.error("Error creating assessment: {}", e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    /**
     * Get all assessments created by a specific user
     */
    @GetMapping("/creator/{creatorId}")
    public ResponseEntity<AssessmentListResponse> getAssessmentsByCreator(
            @PathVariable String creatorId) {
        
        log.info("Fetching assessments for creator: {}", creatorId);
        
        try {
            AssessmentListResponse response = assessmentService.viewAssessmentsCreated(creatorId);
            
            if (response != null) {
                log.info("Found {} assessments for creator: {}", 
                    response.getAssessments() != null ? response.getAssessments().size() : 0, 
                    creatorId);
                return ResponseEntity.ok(response);
            } else {
                log.warn("No assessments found for creator: {}", creatorId);
                return ResponseEntity.notFound().build();
            }
        } catch (Exception e) {
            log.error("Error fetching assessments for creator {}: {}", creatorId, e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    /**
     * Auto-grade an assessment submission
     */
    @PostMapping("/grade")
    public ResponseEntity<GradeResponse> autoGrade(
            @Valid @RequestBody AutoGradeRequest request) {
        
        log.info("Auto-grading assessment with ID: {}", request.getAssessmentId());
        
        try {
            GradeResponse response = assessmentService.autoGrade(request);
            
            if (response != null) {
                log.info("Assessment graded successfully. Grade: {}", response.getGrade());
                return ResponseEntity.ok(response);
            } else {
                log.warn("Unable to grade assessment with ID: {}", request.getAssessmentId());
                return ResponseEntity.badRequest().build();
            }
        } catch (Exception e) {
            log.error("Error grading assessment {}: {}", request.getAssessmentId(), e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    /**
     * Set or update timer for an assessment
     */
    @PutMapping("/timer")
    public ResponseEntity<Void> setTimer(
            @Valid @RequestBody SetTimerRequest request) {
        
        log.info("Setting timer for assessment: {} to {} minutes", 
                request.getAssessmentId(), request.getDurationMinutes());
        
        try {
            assessmentService.setTimer(request);
            log.info("Timer set successfully for assessment: {}", request.getAssessmentId());
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            log.error("Error setting timer for assessment {}: {}", 
                    request.getAssessmentId(), e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    /**
     * Enable/disable question randomization for an assessment
     */
    @PutMapping("/randomize-questions")
    public ResponseEntity<Void> randomizeQuestions(
            @Valid @RequestBody RandomizeQuestionsRequest request) {
        
        log.info("Setting question randomization for assessment: {}", request.getAssessmentId());
        
        try {
            assessmentService.randomizeQuestions(request);
            log.info("Question randomization updated successfully for assessment: {}", 
                    request.getAssessmentId());
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            log.error("Error updating question randomization for assessment {}: {}", 
                    request.getAssessmentId(), e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    /**
     * Enable/disable option randomization for an assessment
     */
    @PutMapping("/randomize-options")
    public ResponseEntity<Void> randomizeOptions(
            @Valid @RequestBody RandomizeOptionsRequest request) {
        
        log.info("Setting option randomization for assessment: {}", request.getAssessmentId());
        
        try {
            assessmentService.randomizeOptions(request);
            log.info("Option randomization updated successfully for assessment: {}", 
                    request.getAssessmentId());
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            log.error("Error updating option randomization for assessment {}: {}", 
                    request.getAssessmentId(), e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    /**
     * Set the correct answer for a question in an assessment
     */
    @PutMapping("/correct-answer")
    public ResponseEntity<Void> setCorrectAnswer(
            @Valid @RequestBody SetCorrectAnswerRequest request) {
        
        log.info("Setting correct answer for question: {} to option: {}", 
                request.getQuestionId(), request.getOptionId());
        
        try {
            assessmentService.setCorrectAnswer(request);
            log.info("Correct answer set successfully for question: {}", request.getQuestionId());
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            log.error("Error setting correct answer for question {}: {}", 
                    request.getQuestionId(), e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    /**
     * Get a specific assessment by ID
     */
    @GetMapping("/{assessmentId}")
    public ResponseEntity<AssessmentResponse> getAssessmentById(
            @PathVariable String assessmentId) {
        
        log.info("Fetching assessment with ID: {}", assessmentId);
        
        try {
            AssessmentResponse response = assessmentService.getAssessmentById(assessmentId);
            log.info("Assessment fetched successfully: {}", assessmentId);
            return ResponseEntity.ok(response);
        } catch (Exception e) {
            log.error("Error fetching assessment {}: {}", assessmentId, e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
    }

    /**
     * Delete an assessment
     */
    @DeleteMapping("/{assessmentId}")
    public ResponseEntity<Void> deleteAssessment(
            @PathVariable String assessmentId) {
        
        log.info("Deleting assessment with ID: {}", assessmentId);
        
        try {
            assessmentService.deleteAssessment(assessmentId);
            log.info("Assessment deleted successfully: {}", assessmentId);
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            log.error("Error deleting assessment {}: {}", assessmentId, e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
    }

    /**
     * Add a question to an assessment
     */
    @PostMapping("/{assessmentId}/questions/{questionId}")
    public ResponseEntity<Void> addQuestionToAssessment(
            @PathVariable String assessmentId,
            @PathVariable String questionId) {
        
        log.info("Adding question {} to assessment {}", questionId, assessmentId);
        
        try {
            assessmentService.addQuestionToAssessment(assessmentId, questionId);
            log.info("Question added successfully to assessment: {}", assessmentId);
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            log.error("Error adding question {} to assessment {}: {}", questionId, assessmentId, e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).build();
        }
    }

    /**
     * Remove a question from an assessment
     */
    @DeleteMapping("/{assessmentId}/questions/{questionId}")
    public ResponseEntity<Void> removeQuestionFromAssessment(
            @PathVariable String assessmentId,
            @PathVariable String questionId) {
        
        log.info("Removing question {} from assessment {}", questionId, assessmentId);
        
        try {
            assessmentService.removeQuestionFromAssessment(assessmentId, questionId);
            log.info("Question removed successfully from assessment: {}", assessmentId);
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            log.error("Error removing question {} from assessment {}: {}", questionId, assessmentId, e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).build();
        }
    }
}

import assessment.manager.services.implementations.AssessmentServiceImpl;
import org.junit.jupiter.api.BeforeEach;

import static org.junit.jupiter.api.Assertions.*;

import assessment.manager.data.models.Assessment;
import assessment.manager.data.repositories.AssessmentRepo;
import assessment.manager.data.repositories.OptionRepo;
import assessment.manager.data.repositories.QuestionRepo;
import assessment.manager.dtos.requests.CreateAssessmentRequest;
import assessment.manager.dtos.responses.AssessmentResponse;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.time.LocalDateTime;
import java.util.ArrayList;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class AssessmentServiceImplTest {

    @Mock
    private AssessmentRepo assessmentRepo;

    @Mock
    private QuestionRepo questionRepo;

    @Mock
    private OptionRepo optionRepo;

    @InjectMocks
    private AssessmentServiceImpl assessmentService;

    private CreateAssessmentRequest validRequest;
    private Assessment savedAssessment;

    @BeforeEach
    void setUp() {
        validRequest = new CreateAssessmentRequest(
                "creator123",
                "Test Assessment",
                "This is a test assessment",
                3600,
                true,
                false
        );

        savedAssessment = Assessment.builder()
                .id("assessment123")
                .creatorId("creator123")
                .title("Test Assessment")
                .description("This is a test assessment")
                .questionIds(new ArrayList<>())
                .timerDuration(3600)
                .isOptionsRandomize(true)
                .isQuestionsRandomize(false)
                .createdAt(LocalDateTime.now())
                .updatedAt(LocalDateTime.now())
                .build();
    }

    @Test
    void createAssessment_ValidRequest_ShouldReturnAssessmentResponse() {
        // Arrange
        when(assessmentRepo.save(any(Assessment.class))).thenReturn(savedAssessment);

        // Act
        AssessmentResponse response = assessmentService.createAssessment(validRequest);

        // Assert
        assertNotNull(response);
        assertEquals("assessment123", response.getId());
        assertEquals("creator123", response.getCreatorId());
        assertEquals("Test Assessment", response.getTitle());
        assertEquals("This is a test assessment", response.getDescription());
        assertEquals(3600, response.getTimerDuration());
        assertTrue(response.isOptionsRandomized());
        assertFalse(response.isQuestionsRandomized());
        assertNotNull(response.getCreatedAt());
        assertNotNull(response.getUpdatedAt());
        assertTrue(response.getQuestions().isEmpty());

        verify(assessmentRepo, times(1)).save(any(Assessment.class));
    }

    @Test
    void createAssessment_NullRequest_ShouldThrowException() {
        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(null);
        });
        
        assertEquals("Assessment request cannot be null", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_NullCreatorId_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithNullCreatorId = new CreateAssessmentRequest(
                null,
                "Test Assessment",
                "This is a test assessment",
                3600,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithNullCreatorId);
        });
        
        assertEquals("Creator ID cannot be null or empty", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_EmptyCreatorId_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithEmptyCreatorId = new CreateAssessmentRequest(
                "   ",
                "Test Assessment",
                "This is a test assessment",
                3600,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithEmptyCreatorId);
        });
        
        assertEquals("Creator ID cannot be null or empty", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_NullTitle_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithNullTitle = new CreateAssessmentRequest(
                "creator123",
                null,
                "This is a test assessment",
                3600,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithNullTitle);
        });
        
        assertEquals("Title cannot be null or empty", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_EmptyTitle_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithEmptyTitle = new CreateAssessmentRequest(
                "creator123",
                "",
                "This is a test assessment",
                3600,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithEmptyTitle);
        });
        
        assertEquals("Title cannot be null or empty", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_NullDescription_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithNullDescription = new CreateAssessmentRequest(
                "creator123",
                "Test Assessment",
                null,
                3600,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithNullDescription);
        });
        
        assertEquals("Description cannot be null or empty", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_EmptyDescription_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithEmptyDescription = new CreateAssessmentRequest(
                "creator123",
                "Test Assessment",
                "   ",
                3600,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithEmptyDescription);
        });
        
        assertEquals("Description cannot be null or empty", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_ZeroTimerDuration_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithZeroTimer = new CreateAssessmentRequest(
                "creator123",
                "Test Assessment",
                "This is a test assessment",
                0,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithZeroTimer);
        });
        
        assertEquals("Timer duration must be positive (greater than 0 seconds)", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_NegativeTimerDuration_ShouldThrowException() {
        // Arrange
        CreateAssessmentRequest requestWithNegativeTimer = new CreateAssessmentRequest(
                "creator123",
                "Test Assessment",
                "This is a test assessment",
                -100,
                true,
                false
        );

        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            assessmentService.createAssessment(requestWithNegativeTimer);
        });
        
        assertEquals("Timer duration must be positive (greater than 0 seconds)", exception.getMessage());
        verify(assessmentRepo, never()).save(any(Assessment.class));
    }

    @Test
    void createAssessment_ValidRequest_ShouldVerifyAssessmentResponseConversion() {
        // Arrange
        when(assessmentRepo.save(any(Assessment.class))).thenReturn(savedAssessment);

        // Act
        AssessmentResponse response = assessmentService.createAssessment(validRequest);

        // Assert
        assertNotNull(response);
        assertEquals(savedAssessment.getId(), response.getId());
        assertEquals(savedAssessment.getCreatorId(), response.getCreatorId());
        assertEquals(savedAssessment.getTitle(), response.getTitle());
        assertEquals(savedAssessment.getDescription(), response.getDescription());
        assertEquals(savedAssessment.getTimerDuration(), response.getTimerDuration());
        assertEquals(savedAssessment.isOptionsRandomize(), response.isOptionsRandomized());
        assertEquals(savedAssessment.isQuestionsRandomize(), response.isQuestionsRandomized());
        assertNotNull(response.getCreatedAt());
        assertNotNull(response.getUpdatedAt());
        assertNotNull(response.getQuestions());
        assertTrue(response.getQuestions().isEmpty());

        verify(assessmentRepo, times(1)).save(any(Assessment.class));
    }


